import { MakeLogicType, actions, afterMount, kea, listeners, path } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import { getCurrentTeamId } from 'lib/utils/getAppContext'

import { conversationsIncidentsDismissCreate, conversationsIncidentsList } from '../../generated/api'
import type { TicketIncidentApi } from '../../generated/api.schemas'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface incidentBannerLogicValues {
    activeIncidents: TicketIncidentApi[]
    activeIncidentsLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface incidentBannerLogicActions {
    dismissIncident: (incidentId: string) => {
        incidentId: string
    }
    loadActiveIncidents: () => any
    loadActiveIncidentsFailure: (error: string, errorObject?: any) => { error: string; errorObject?: any }
    loadActiveIncidentsSuccess: (
        activeIncidents: TicketIncidentApi[],
        payload?: any
    ) => { activeIncidents: TicketIncidentApi[]; payload?: any }
}

export type incidentBannerLogicType = MakeLogicType<incidentBannerLogicValues, incidentBannerLogicActions>

export const incidentBannerLogic = kea<incidentBannerLogicType>([
    path(['products', 'conversations', 'frontend', 'components', 'IncidentBanner', 'incidentBannerLogic']),
    actions({
        dismissIncident: (incidentId: string) => ({ incidentId }),
    }),
    loaders({
        activeIncidents: [
            [] as TicketIncidentApi[],
            {
                loadActiveIncidents: async () => {
                    const response = await conversationsIncidentsList(String(getCurrentTeamId()), {
                        status: 'active',
                    })
                    return response.results ?? []
                },
            },
        ],
    }),
    listeners(({ actions, cache }) => ({
        dismissIncident: async ({ incidentId }) => {
            // The banner's close button can't show a spinner; swallow re-clicks instead.
            if (cache.dismissing) {
                return
            }
            cache.dismissing = true
            try {
                await conversationsIncidentsDismissCreate(String(getCurrentTeamId()), incidentId)
                actions.loadActiveIncidents()
            } catch {
                lemonToast.error('Failed to dismiss incident')
            } finally {
                cache.dismissing = false
            }
        },
    })),
    afterMount(({ actions }) => {
        actions.loadActiveIncidents()
    }),
])
